node --input-type=module << 'EOF'
import { chromium } from '/home/travis/Lookitry/openclaw/node_modules/playwright/index.mjs';

const browser = await chromium.connectOverCDP('http://127.0.0.1:18800');
const context = browser.contexts()[0] || await browser.newContext();
const page = context.pages()[0] || await context.newPage();

console.log('=== INVESTIGATING FIVERR ACCOUNT TYPE ===\n');

// Navigate to homepage to see if there's a "Become a Seller" option visible
await page.goto('https://www.fiverr.com', { timeout: 30000 });
await page.waitForLoadState('networkidle', { timeout: 15000 }).catch(() => {});

await page.screenshot({ path: '/tmp/fiverr_screenshot_homepage.png' });

// Get all visible text to find "become a seller" on the homepage
const bodyText = await page.evaluate(() => document.body.innerText);
const lines = bodyText.split('\n').filter(l => l.trim().length > 0);

// Find lines with "seller" or "become"
const sellerLines = lines.filter(l => l.toLowerCase().includes('seller') || l.toLowerCase().includes('become'));
console.log('Lines containing "seller" or "become":');
sellerLines.forEach(l => console.log('  ', l.substring(0, 100)));

// Look for any "Start Selling" button or link
console.log('\n--- Looking for start selling options ---');
const startSelling = await page.$$eval('a, button', els => 
  els.filter(el => {
    const text = el.innerText.toLowerCase();
    return text.includes('start selling') || text.includes('become a seller') || text.includes('switch to seller');
  }).map(el => ({ tag: el.tagName, text: el.innerText.trim(), href: el.href || '' }))
);
console.log('Start selling options:', JSON.stringify(startSelling, null, 2));

// Check cookies for account type
console.log('\n--- Cookie Analysis ---');
const cookies = await context.cookies();
cookies.forEach(c => {
  if (c.name.includes('seller') || c.name.includes('user') || c.name.includes('account')) {
    console.log(`${c.name}: ${c.value}`);
  }
});

// Check local storage
const localStorage = await page.evaluate(() => {
  const data = {};
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (key.includes('seller') || key.includes('user') || key.includes('type')) {
      data[key] = localStorage.getItem(key);
    }
  }
  return data;
});
console.log('LocalStorage seller keys:', JSON.stringify(localStorage, null, 2));

// Check session storage
const sessionStorage = await page.evaluate(() => {
  const data = {};
  for (let i = 0; i < sessionStorage.length; i++) {
    const key = sessionStorage.key(i);
    if (key.includes('seller') || key.includes('user') || key.includes('type')) {
      data[key] = sessionStorage.getItem(key);
    }
  }
  return data;
});
console.log('SessionStorage seller keys:', JSON.stringify(sessionStorage, null, 2));

console.log('\nCurrent logged in user:', await page.evaluate(() => {
  // Look for user name in various places
  const elements = document.querySelectorAll('[class*="user"], [class*="account"], [class*="profile"]');
  return Array.from(elements).map(el => el.innerText.trim()).filter(t => t.length > 0 && t.length < 50);
}));

await browser.close();
EOF

