const browser = await chromium.connectOverCDP('http://127.0.0.1:18800');
const context = browser.contexts()[0] || await browser.newContext();
const page = context.pages()[0] || await context.newPage();

console.log('=== USING JS CLICK FOR CATEGORY ===\n');

await page.goto('https://www.fiverr.com/users/rebecca_ashfd/manage_gigs/new?wizard=0&tab=general', { timeout: 30000 });
await page.waitForLoadState('networkidle', { timeout: 15000 }).catch(() => {});
await page.waitForTimeout(3000);

// Fix the title
const titleInput = page.locator('input[type="text"], textarea').first();
await titleInput.fill('be your UGC female model for your brand');
await page.waitForTimeout(1000);

// Use JS to open the category dropdown and select Video & Animation
console.log('Opening category dropdown via JS...');
const categoryResult = await page.evaluate(() => {
  // Find the category dropdown trigger
  const allTextEls = Array.from(document.querySelectorAll('*')).filter(el => el.children.length === 0);
  const catSpan = allTextEls.find(el => el.innerText === 'DIGITAL MARKETING');

  if (catSpan) {
    // Click the parent or sibling to open dropdown
    let parent = catSpan.parentElement;
    while (parent) {
      if (parent.offsetWidth > 0 && parent.offsetHeight > 0) {
        // Find a clickable element
        const btns = parent.querySelectorAll('button, [role="button"]');
        if (btns.length > 0) {
          btns[0].click();
          return { clicked: true, text: parent.innerText.substring(0, 200) };
        }
      }
      parent = parent.parentElement;
    }
  }
