import { chromium } from '/home/travis/Lookitry/openclaw/node_modules/playwright/index.mjs';

const browser = await chromium.connectOverCDP('http://127.0.0.1:18800');
const context = browser.contexts()[0] || await browser.newContext();
const page = context.pages()[0] || await context.newPage();

console.log('=== INSPECTING CURRENT ONBOARDING STATE ===\n');

await page.goto('https://www.fiverr.com/seller_onboarding/0', { timeout: 30000 });
await page.waitForLoadState('networkidle', { timeout: 15000 }).catch(() => {});
await page.waitForTimeout(3000);

// List all visible interactive elements
const interactive = await page.evaluate(() => {
  const els = Array.from(document.querySelectorAll('button, a, [role="button"], input, select, textarea'));
  return els
    .filter(el => {
      const style = window.getComputedStyle(el);
      return style.display !== 'none' && style.visibility !== 'hidden' && el.offsetWidth > 0 && el.offsetHeight > 0;
    })
    .map(el => ({
      tag: el.tagName,
      type: el.type || 'N/A',
      text: el.innerText?.trim().substring(0, 80) || '',
      placeholder: el.placeholder || '',
      ariaLabel: el.getAttribute('aria-label') || '',
      id: el.id || '',
      class: el.className.substring(0, 80)
    }));
});

console.log('Visible interactive elements:');
interactive.forEach(el => console.log(JSON.stringify(el)));

// Also get the full visible text
const visibleText = await page.evaluate(() => {
  const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, {
    acceptNode: function(node) {
      const style = window.getComputedStyle(node.parentElement);
      if (style.display === 'none' || style.visibility === 'hidden') return NodeFilter.FILTER_REJECT;
      if (node.parentElement.tagName === 'SCRIPT' || node.parentElement.tagName === 'STYLE') return NodeFilter.FILTER_REJECT;
      if (!node.nodeValue?.trim()) return NodeFilter.FILTER_REJECT;
      return NodeFilter.FILTER_ACCEPT;
    }
  });
  const texts = [];
  let node;
  while (node = walker.nextNode()) texts.push(node.nodeValue.trim());
  return texts.filter(t => t.length > 0);
});

console.log('\nVisible text:');
visibleText.slice(0, 60).forEach(t => console.log(' ', t));

await browser.close();
EOF

