import { chromium } from '/home/travis/Lookitry/openclaw/node_modules/playwright/index.mjs';

const browser = await chromium.connectOverCDP('http://127.0.0.1:18800');
const context = browser.contexts()[0] || await browser.newContext();
const page = context.pages()[0] || await context.newPage();

console.log('=== FULL PAGE SNAPSHOT ===\n');

await page.goto('https://www.fiverr.com/users/rebecca_ashfd/manage_gigs/new?wizard=0&tab=general', { timeout: 30000 });
await page.waitForTimeout(5000);

await page.screenshot({ path: '/tmp/fiverr_full_snapshot.png' });

// Get ALL visible text on page using tree walker
const allVisibleText = await page.evaluate(() => {
  const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, {
    acceptNode: (node) => {
      const style = window.getComputedStyle(node.parentElement);
      if (style.display === 'none' || style.visibility === 'hidden') return NodeFilter.FILTER_REJECT;
      if (!node.nodeValue?.trim()) return NodeFilter.FILTER_REJECT;
      if (node.parentElement.tagName === 'SCRIPT') return NodeFilter.FILTER_REJECT;
      return NodeFilter.FILTER_ACCEPT;
    }
  });
  const texts = [];
  let node;
  while (node = walker.nextNode()) {
    texts.push(node.nodeValue.trim());
  }
  return texts.filter(t => t.length > 0 && t.length < 200);
});

console.log('All visible text:');
allVisibleText.forEach(t => console.log(' ', t));

await browser.close();
EOF

